// 读取规则.docx 文件内容
var docPath = "/Users/cassia/Desktop/dyx/wpsjs/3. 中水设计文档校排/规则.docx";
var app = Application;
var docs = app.Documents;

try {
    // 查找已打开的规则.docx
    var ruleDoc = null;
    for (var i = 1; i <= docs.Count; i++) {
        var d = docs.Item(i);
        if (d.Name === "规则.docx") {
            ruleDoc = d;
            break;
        }
    }

    if (!ruleDoc) {
        return { success: false, error: "未找到规则.docx 文件" };
    }

    // 读取全文内容
    var content = ruleDoc.Content.Text;
    return { success: true, content: content };
} catch (e) {
    return { success: false, error: String(e) };
}
